const jwt = require('jsonwebtoken');
const cacheManager = require('cache-manager');
const memoryCache = new cacheManager.caching({ store: 'memory', max: 100, ttl: 60 }); // Max entries of 100 for a minute TTL

// Middleware function to authenticate users with JWTs and extract user information from the token
function jwtAuthMiddleware(req, res, next) {
    const authHeader = req.headers['authorization'];
    const token = authHeader && authHeader.split(' ')[1]; // Extract the JWT from the header
  
    if (token == null) return res.sendStatus(401); // If there is no token, send a 401 Unauthorized response

    jwt.verify(token, process.env.ACCESS_TOKEN_SECRET, async (err, user) => {
        if (err) return res.sendStatus(403); // If the token verification fails, send a 403 Forbidden response
        
        const cacheKey = `blocklist:${user.username}`;
        const isInBlocklist = await memoryCache.get(cacheKey);
  
        if (isInBlocklist) {
            return res.sendStatus(401); // If the user is in the blocklist, send a 401 Unauthorized response
        } else {
            req.user = user; // Store the decoded JWT payload in the request object for later use
            next(); // Proceed to the route handler
        }
    });
}